export class AXUploadRequest {
  get name(): string;
  get ext(): string;
  get size(): number;
  get file(): File;

  progress: Signal<number>;
  estimateTime: Signal<number>;
  status: Signal<AXUploadStatus>;
  message: Signal<string | null>;
  isDetermined: Signal<boolean>;

  metaData: any;

  onCancel: Subject<void>;
  onStart: Subject<void>;
  onFailed: Subject<void>;
  onComplete: BehaviorSubject<void>;

  constructor(uploadFile: File);

  setTransferredBytes(value: number): void;
  upload(): Promise<void>;
  cancel(): void;
  redo(): void;
  error(message: string): void;
  finish(data?: any): void;
}
